function draw_points(b){for(var d=b.split("<#ROW#>"),b="",c=0;c<d.length;c++){var a=d[c].split("<#COL#>");b+="<img src='"+rootUri+"Content/Images/TaxiLocations/taxi-point.png' style='position:absolute;left:"+a[2]+"px; top:"+a[3]+"px' onmouseover='onOverPoint(\""+a[0]+'","'+a[1]+'","'+a[2]+'","'+a[3]+'","'+a[4]+"\")' onmouseout='onOutPoint()' />"}$("#google_map").html(b)}$(function(){draw_points(points_data)});function clickMap(){var a=Math.random()*1024,b=Math.random()*768;$("#stand_name").val("");$("#gps_address").val("");$("#longitude").val(a);$("#latitude").val(b);$("#stand_type").val("");$("#add-dialog").show()}function closeMe(){$("#add-dialog").hide()}function onOverPoint(d,c,a,b,e){$("#info_stand_name").val(d);$("#info_gps_address").val(c);$("#info_longitude").val(a);$("#info_latitude").val(b);$("#info_stand_type").val(e);$("#point-info-dlg").css("left",a+"px");$("#point-info-dlg").css("top",Number(b)+40+"px");$("#point-info-dlg").show()}function onOutPoint(){$("#point-info-dlg").hide()}function checkValid(){if($("#stand_name").val()==""){alert("please input Taxi Stand name.");return false}if($("#gps_address").val()==""){alert("please input GPS Address.");return false}return true}function addPoint(){checkValid()&&$.ajax({async:false,type:"post",dataType:"json",url:rootUri+"TaxiLocations/AddPoint",data:{stand_name:$("#stand_name").val(),gps_address:$("#gps_address").val(),longitude:$("#longitude").val(),latitude:$("#latitude").val(),stand_type:$("#taxi_stand_type").val()},success:function(b){if(b.success=="ok"){var a=$("#google_map").html();a+="<img src='"+rootUri+"Content/Images/TaxiLocations/taxi-point.png' style='position:absolute;left:"+$("#longitude").val()+"px; top:"+$("#latitude").val()+"px' onmouseover='onOverPoint(\""+$("#stand_name").val()+'","'+$("#gps_address").val()+'","'+$("#longitude").val()+'","'+$("#latitude").val()+'","'+$("#taxi_stand_type").val()+"\")' onmouseout='onOutPoint()' />";$("#google_map").html(a);closeMe();alert("Successfully Added!")}else $("#span_Filter").html(b.retStr)},error:ErrorProcess})}function cancels(){document.location.href=rootUri+"TaxiLocations"};